CREATE OR REPLACE FUNCTION fpa_get_last_calintfrom_date (as_conno char) RETURNS timestamp(0) AS $body$
DECLARE

  ld_date timestamp(0);

BEGIN
   select	sc_lon_m_loan_card.last_calcint_date into STRICT ld_date
  from		sc_lon_m_loan_card
  where (sc_lon_m_loan_card.loan_contract_no = as_conno);

  return ld_date;
exception when others then CALL spa_dberror('fpa_get_last_calintfrom_date');
end;
